            path: 'scripts/validate-drawio.py',
            role: 'script',
            content:
                '#!/usr/bin/env python3\n"""validate-drawio.py — well-formedness and structural validator for .drawio (mxGraph XML) files.\n\nThe build-mode safety net. Checks, per page (`<diagram>`):\n  - the file is well-formed XML and contains <mxfile>/<diagram>/<mxGraphModel>/<root>;\n  - the required root cells id="0" and id="1" are present;\n  - cell ids are unique;\n  - every edge\'s source/target (when set) resolves to an existing cell id;\n  - every cell\'s parent resolves to an existing cell id;\n  - no self-closing edge cells (they will not render);\n  - reports orphaned vertices (no incident edge) as warnings, not errors.\n\nCompressed/encoded diagrams (deflate + base64 inside <diagram>) cannot be structurally\nchecked without decoding — these are reported as a SKIP with a clear note (graceful degradation),\nnot a failure.\n\nUsage:  python3 validate-drawio.py <path/to/diagram.drawio> [more.drawio ...]\nExit codes: 0 = all files valid; 1 = at least one error; 2 = usage error.\n"""\nimport re\nimport sys\nimport xml.etree.ElementTree as ET\n\n\ndef looks_encoded(diagram_el) -> bool:\n    """A <diagram> whose text is a long base64 blob with no child elements is compressed."""\n    if len(list(diagram_el)) > 0:\n        return False\n    text = (diagram_el.text or "").strip()\n    return len(text) > 40 and re.fullmatch(r"[A-Za-z0-9+/=\\s]+", text) is not None\n\n\ndef validate_model(root_el):\n    """Validate a single <root> element. Returns (errors, warnings)."""\n    errors, warnings = [], []\n    cells = root_el.findall(".//mxCell")\n    ids, dup = set(), set()\n    for c in cells:\n        cid = c.get("id")\n        if cid is None:\n            errors.append("an mxCell has no id attribute")\n            continue\n        if cid in ids:\n            dup.add(cid)\n        ids.add(cid)\n    for d in sorted(dup):\n        errors.append(f"duplicate cell id: {d!r}")\n\n    for required in ("0", "1"):\n        if required not in ids:\n            errors.append(f"missing required root cell id={required!r}")\n\n    incident = set()\n    for c in cells:\n        cid = c.get("id")\n        is_edge = c.get("edge") == "1"\n        is_vertex = c.get("vertex") == "1"\n        parent = c.get("parent")\n        if parent is not None and parent not in ids:\n            errors.append(f"cell {cid!r} has parent {parent!r} which does not exist")\n        if is_edge:\n            for end in ("source", "target"):\n                ref = c.get(end)\n                if ref is not None:\n                    if ref not in ids:\n                        errors.append(f"edge {cid!r} {end}={ref!r} does not resolve to a cell")\n                    else:\n                        incident.add(ref)\n            # self-closing edge (no mxGeometry child) will not render\n            if c.find("mxGeometry") is None:\n                errors.append(f"edge {cid!r} has no <mxGeometry> child — self-closing edges do not render")\n        if is_vertex:\n            # track so we can warn about orphans below\n            pass\n\n    for c in cells:\n        if c.get("vertex") == "1":\n            cid = c.get("id")\n            if cid not in incident and cid not in ("0", "1"):\n                # only warn for top-level shapes, not container children\n                if c.get("parent") in ("1", None):\n                    warnings.append(f"vertex {cid!r} (value={c.get(\'value\')!r}) has no connections (orphan)")\n    return errors, warnings\n\n\ndef validate_file(path: str) -> bool:\n    print(f"== {path}")\n    try:\n        with open(path, "r", encoding="utf-8") as f:\n            content = f.read()\n    except OSError as e:\n        print(f"  ERROR: cannot read file: {e}")\n        return False\n    try:\n        tree = ET.fromstring(content)\n    except ET.ParseError as e:\n        print(f"  ERROR: not well-formed XML: {e}")\n        return False\n\n    if tree.tag != "mxfile":\n        print("  WARN: root element is not <mxfile> — unusual for a .drawio file")\n\n    diagrams = tree.findall("diagram")\n    if not diagrams:\n        # maybe a bare <mxGraphModel>\n        roots = tree.findall(".//root")\n        if not roots:\n            print("  ERROR: no <diagram> or <root> found")\n            return False\n        diagrams = [None] * 0  # handled below via roots\n        ok = True\n        for r in roots:\n            errs, warns = validate_model(r)\n            ok = ok and not errs\n            for w in warns:\n                print(f"  WARN: {w}")\n            for e in errs:\n                print(f"  ERROR: {e}")\n        if ok:\n            print("  OK")\n        return ok\n\n    ok = True\n    for i, d in enumerate(diagrams, 1):\n        name = d.get("name", f"Page-{i}")\n        if looks_encoded(d):\n            print(f"  SKIP page {i!r} ({name}): compressed/encoded content — decode before structural validation")\n            continue\n        root_el = d.find(".//root")\n        if root_el is None:\n            print(f"  ERROR page {name}: no <root> element")\n            ok = False\n            continue\n        errs, warns = validate_model(root_el)\n        for w in warns:\n            print(f"  WARN page {name}: {w}")\n        for e in errs:\n            print(f"  ERROR page {name}: {e}")\n        if errs:\n            ok = False\n        elif not warns:\n            print(f"  OK page {name}")\n    return ok\n\n\ndef main(argv):\n    if len(argv) < 2:\n        print("usage: validate-drawio.py <file.drawio> [more...]", file=sys.stderr)\n        return 2\n    all_ok = True\n    for path in argv[1:]:\n        all_ok = validate_file(path) and all_ok\n    print("\\nVALID" if all_ok else "\\nINVALID")\n    return 0 if all_ok else 1\n\n\nif __name__ == "__main__":\n    sys.exit(main(sys.argv))\n',
